import React, { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { Button, Form } from "react-bootstrap";

const API_URL = "http://127.0.0.1:8000";

export default function InvoiceDetail() {
  const location = useLocation();
  const navigate = useNavigate();
  const [invoice, setInvoice] = useState(location.state.invoice);
  const [isEditing, setIsEditing] = useState(false);

  const handleEditChange = (e) => {
    setInvoice({ ...invoice, [e.target.name]: e.target.value });
  };

  const saveEdit = async () => {
    await fetch(`${API_URL}/update/${invoice.id}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(invoice),
    });
    setIsEditing(false);
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Invoice Details</h2>
      <div className="border p-4 rounded shadow-md">
        <div className="mb-3">
          <strong>ID:</strong> {invoice.id}
        </div>
        <div className="mb-3">
          <strong>Filename:</strong> {invoice.filename}
        </div>
        <div className="mb-3">
          <strong>Amount:</strong>{" "}
          {isEditing ? (
            <Form.Control type="text" name="amount" value={invoice.amount} onChange={handleEditChange} />
          ) : (
            <span onClick={() => setIsEditing(true)}>{invoice.amount}</span>
          )}
        </div>
        <div className="mb-3">
          <strong>Date:</strong>{" "}
          {isEditing ? (
            <Form.Control type="date" name="date" value={invoice.date} onChange={handleEditChange} />
          ) : (
            <span onClick={() => setIsEditing(true)}>{invoice.date}</span>
          )}
        </div>
        <div className="mb-3">
          <strong>Order #:</strong>{" "}
          {isEditing ? (
            <Form.Control type="text" name="order_number" value={invoice.order_number} onChange={handleEditChange} />
          ) : (
            <span onClick={() => setIsEditing(true)}>{invoice.order_number}</span>
          )}
        </div>
        <div className="mb-3">
          <strong>Merchant:</strong>{" "}
          {isEditing ? (
            <Form.Control type="text" name="merchant" value={invoice.merchant} onChange={handleEditChange} />
          ) : (
            <span onClick={() => setIsEditing(true)}>{invoice.merchant}</span>
          )}
        </div>
        <div className="mb-3">
          <strong>Category:</strong>{" "}
          {isEditing ? (
            <Form.Control type="text" name="category" value={invoice.category} onChange={handleEditChange} />
          ) : (
            <span onClick={() => setIsEditing(true)}>{invoice.category || "Uncategorized"}</span>
          )}
        </div>
        <div className="flex space-x-4">
          <Button className="bg-blue-500 text-white p-2 rounded" onClick={() => navigate("/")}>
            Back
          </Button>
          {isEditing && (
            <Button className="bg-green-500 text-white p-2 rounded" onClick={saveEdit}>
              Save Changes
            </Button>
          )}
        </div>
      </div>
    </div>
  );
}
